import{c as t,Q as a,j as r,m as o}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"Environment Variables","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin/environment-variables.md","filePath":"guide/admin/environment-variables.md","lastUpdated":1778912818000}'),n={name:"guide/admin/environment-variables.md"};function i(s,e,l,d,c,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="environment-variables" tabindex="-1">Environment Variables <a class="header-anchor" href="#environment-variables" aria-label="Permalink to &quot;Environment Variables&quot;">​</a></h1><p>The <strong>Environment Variables</strong> page manages every variable the Console hands to the deployed services. Variables can be plain values, references to Kubernetes secrets, or references to ConfigMaps. They can be set globally and <strong>overridden per instance</strong>.</p><p>The page has three tabs.</p><h2 id="variables-tab" tabindex="-1">Variables tab <a class="header-anchor" href="#variables-tab" aria-label="Permalink to &quot;Variables tab&quot;">​</a></h2><p>The default. A flat list of every variable with per-instance overrides expandable per row.</p><h3 id="toolbar" tabindex="-1">Toolbar <a class="header-anchor" href="#toolbar" aria-label="Permalink to &quot;Toolbar&quot;">​</a></h3><p>A single <strong>token-aware</strong> filter field with these tokens:</p><ul><li><code>type:value</code>, <code>type:secretKeyRef</code>, <code>type:configMapKeyRef</code></li><li><code>service:&lt;name&gt;</code></li><li><code>instance:&lt;name&gt;</code> — filters to variables that have an override on the given instance</li></ul><p>Negation works: <code>-type:value</code>, <code>-service:nodejs</code>.</p><p>Free text matches variable keys and service names.</p><p>Count chip shows filtered vs. total. <strong>Add Variable</strong> button is top right.</p><h3 id="columns" tabindex="-1">Columns <a class="header-anchor" href="#columns" aria-label="Permalink to &quot;Columns&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Key</strong></td><td>Monospace, bold. Auto-uppercase on entry. Has an expand chevron.</td></tr><tr><td><strong>Type</strong></td><td>Badge — value, secretKeyRef, or configMapKeyRef.</td></tr><tr><td><strong>Default</strong></td><td>The value, or the <code>name/key</code> ref. Monospace, truncated.</td></tr><tr><td><strong>Services</strong></td><td>Up to two service chips; &quot;+N more&quot; popover for the rest.</td></tr><tr><td><strong>Description</strong></td><td>Short description, truncated.</td></tr><tr><td><strong>Actions</strong></td><td>Edit and delete icons.</td></tr></tbody></table><h3 id="expanded-row-—-per-instance-overrides" tabindex="-1">Expanded row — per-instance overrides <a class="header-anchor" href="#expanded-row-—-per-instance-overrides" aria-label="Permalink to &quot;Expanded row — per-instance overrides&quot;">​</a></h3><p>Click the chevron to expand. A sub-table shows every instance with an override:</p><ul><li>Instance name and environment.</li><li>Override value or ref.</li><li>Last updated timestamp with the user who changed it.</li><li>Edit / Delete icons.</li></ul><p>You can also see which instances have no override (&quot;Using default&quot;).</p><p>Inside the sub-table, the filter from the main toolbar still applies — <code>instance:prod</code> narrows the visible instances.</p><h3 id="editing-inline" tabindex="-1">Editing inline <a class="header-anchor" href="#editing-inline" aria-label="Permalink to &quot;Editing inline&quot;">​</a></h3><p>The Add / Edit row uses inline editing — the row background tints info-colour and the cells become form inputs:</p><ul><li><strong>Key</strong> — auto-uppercase, locked when editing.</li><li><strong>Type</strong> dropdown.</li><li><strong>Default Value</strong> — plain text for <code>value</code>, <code>name/key</code> format for refs.</li><li><strong>Services</strong> — multi-select (services must already exist on the <a href="./release-configuration">Release Configuration</a> page).</li><li><strong>Description</strong>.</li></ul><p>Click <strong>Save</strong> to persist, <strong>Cancel</strong> to discard. Errors appear inline below the row.</p><h3 id="setting-an-instance-override" tabindex="-1">Setting an instance override <a class="header-anchor" href="#setting-an-instance-override" aria-label="Permalink to &quot;Setting an instance override&quot;">​</a></h3><p>Inside an expanded row, click the <strong>+</strong> icon (or the pencil if an override already exists) next to an instance:</p><ul><li>A modal opens for the override value.</li><li>The override can be a plain value or a <code>name/key</code> ref.</li><li>Click <strong>Save</strong>.</li></ul><p>To remove an override, click the trash icon — the instance reverts to the default.</p><p>Decommissioned instances are excluded from the override table.</p><h2 id="by-service-tab" tabindex="-1">By Service tab <a class="header-anchor" href="#by-service-tab" aria-label="Permalink to &quot;By Service tab&quot;">​</a></h2><p>The same variables, grouped by service.</p><ul><li><strong>Service filter</strong> — search box at the top filters which services show.</li><li>Each service is a collapsible card with the count of assigned variables.</li><li>Inside an expanded service: a table of assigned variables with Remove buttons.</li><li><strong>Add Variable</strong> button opens a picker showing unassigned variables — pick one or many, then close.</li></ul><p>This view is most useful when you need to see &quot;what does <em>this service</em> see?&quot; rather than &quot;where is <em>this variable</em> used?&quot;</p><h2 id="version-history-tab" tabindex="-1">Version History tab <a class="header-anchor" href="#version-history-tab" aria-label="Permalink to &quot;Version History tab&quot;">​</a></h2><p>Every change to environment variables is versioned globally.</p><h3 id="columns-1" tabindex="-1">Columns <a class="header-anchor" href="#columns-1" aria-label="Permalink to &quot;Columns&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Version</strong></td><td><code>v1</code>, <code>v2</code>, <code>v3</code>… in monospace.</td></tr><tr><td><strong>Changes</strong></td><td>Multi-line — change action badge, key, scope.</td></tr><tr><td><strong>Changed By</strong></td><td>User avatar and name.</td></tr><tr><td><strong>Date</strong></td><td>Absolute timestamp.</td></tr></tbody></table><h3 id="pagination" tabindex="-1">Pagination <a class="header-anchor" href="#pagination" aria-label="Permalink to &quot;Pagination&quot;">​</a></h3><p>50 entries per page. Click <strong>Load More</strong> to fetch more.</p><p>The version history is global — releases that touch environment variables produce entries here, and per-instance override changes do too.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>The Console resolves a variable to a concrete value by consulting (1) instance override → (2) global default. If a service does not see the expected value, the most likely cause is an override at the instance level.</li><li>Secret refs and ConfigMap refs are validated at deploy time by the agent, not at save time here. A typo in <code>name/key</code> will surface as a deployment failure.</li><li>Decommissioned instances do not appear in override tables and do not receive variable changes.</li><li>The version history is your friend for &quot;who changed this and when&quot;.</li></ul>',40)])])}const v=t(n,[["render",i]]);export{u as __pageData,v as default};
